 246→const VALID_ICON_CHOICES = new Set<string>([
 247→  'auto',
 248→  'url',
 249→  'file',
 250→  'deeplink',
 251→]);
 252→
 253→function isIconChoice(value: string): value is IconChoice {
 254→  return VALID_ICON_CHOICES.has(value);
