 256→
 257→function resolveIcon(iconChoice: IconChoice, type: QuicklinkType): ReactNode {
 258→  if (iconChoice === 'auto') return getQuicklinkIcon(type);
 259→  if (isQuicklinkType(iconChoice)) return getQuicklinkIcon(iconChoice);
 260→  return getQuicklinkIcon(type);
 261→}
