 283→function EditQuicklinkView({ quicklink, onSubmit }: EditQuicklinkViewProps) {
 284→  const [form, setForm] = useState<QuicklinkFormState>(() => {
 285→    if (quicklink) {
 286→      return {
 287→        name: quicklink.name,
 288→        link: quicklink.link,
 289→        type: quicklink.type,
 290→        iconChoice: 'auto',
 291→        application: quicklink.application ?? '',
 292→      };
 293→    }
 294→    return INITIAL_FORM;
 295→  });
 296→  const [errors, setErrors] = useState<
 297→    Partial<Record<keyof QuicklinkFormState, string>>
 298→  >({});
 299→
 300→  const handleSubmit = useCallback(() => {
 301→    const newErrors: Partial<Record<keyof QuicklinkFormState, string>> = {};
 302→    if (!form.name.trim()) {
 303→      newErrors.name = 'Name is required';
 304→    }
 305→    if (!form.link.trim()) {
 306→      newErrors.link = 'Link is required';
 307→    }
 308→    setErrors(newErrors);
 309→    if (Object.keys(newErrors).length > 0) return;
 310→    onSubmit(form);
 311→  }, [
 312→    form,
 313→    onSubmit,
 314→  ]);
 315→
 316→  useKeyboardShortcut(
 317→    {
 318→      key: 'Enter',
 319→      meta: true,
 320→    },
 321→    handleSubmit,
 322→  );
 323→
 324→  return (
 325→    <Form onSubmit={handleSubmit}>
 326→      <FormTextField
 327→        label="Name"
 328→        value={form.name}
 329→        onChange={v =>
 330→          setForm(prev => ({
 331→            ...prev,
 332→            name: v,
 333→          }))
 334→        }
 335→        placeholder="e.g. GitHub Dashboard"
 336→        error={errors.name}
 337→        autoFocus
 338→      />
 339→      <FormTextField
 340→        label="Link"
 341→        value={form.link}
 342→        onChange={v =>
 343→          setForm(prev => ({
 344→            ...prev,
 345→            link: v,
 346→          }))
 347→        }
 348→        placeholder="e.g. https://github.com or ~/Documents"
 349→        description="Use {query} as placeholder for dynamic input"
 350→        error={errors.link}
 351→      />
 352→      <FormDropdown
 353→        label="Type"
 354→        value={form.type}
 355→        onChange={v => {
 356→          if (isQuicklinkType(v)) {
 357→            setForm(prev => ({
 358→              ...prev,
 359→              type: v,
 360→            }));
 361→          }
 362→        }}
 363→        options={TYPE_OPTIONS}
 364→      />
 365→      <FormDropdown
 366→        label="Icon"
 367→        value={form.iconChoice}
 368→        onChange={v => {
 369→          if (isIconChoice(v)) {
 370→            setForm(prev => ({
 371→              ...prev,
 372→              iconChoice: v,
 373→            }));
 374→          }
 375→        }}
 376→        options={ICON_OPTIONS}
 377→      />
 378→      <FormTextField
 379→        label="Open With"
 380→        value={form.application}
 381→        onChange={v =>
 382→          setForm(prev => ({
 383→            ...prev,
 384→            application: v,
 385→          }))
 386→        }
 387→        placeholder="e.g. Safari (optional)"
 388→        description="Application to open the link with"
 389→      />
 390→    </Form>
 391→  );
 392→}
