 400→function QueryInputView({
 401→  quicklink,
 402→  onSubmit,
 403→  onCancel,
 404→}: QueryInputViewProps) {
 405→  const [inputValue, setInputValue] = useState('');
 406→
 407→  const handleSubmit = useCallback(() => {
 408→    if (!inputValue.trim()) return;
 409→    const resolved = quicklink.link.replaceAll(
 410→      '{query}',
 411→      encodeURIComponent(inputValue.trim()),
 412→    );
 413→    onSubmit(resolved);
 414→  }, [
 415→    inputValue,
 416→    quicklink.link,
 417→    onSubmit,
 418→  ]);
 419→
 420→  useKeyboardShortcut(
 421→    {
 422→      key: 'Enter',
 423→      meta: true,
 424→    },
 425→    handleSubmit,
 426→  );
 427→  useKeyboardShortcut({ key: 'Escape' }, onCancel);
 428→
 429→  return (
 430→    <Form onSubmit={handleSubmit}>
 431→      <FormTextField
 432→        label="Query"
 433→        value={inputValue}
 434→        onChange={setInputValue}
 435→        placeholder={`Enter query for ${quicklink.name}...`}
 436→        description={`Opens: ${quicklink.link.replace('{query}', '<your input>')}`}
 437→        autoFocus
 438→      />
 439→    </Form>
 440→  );
 441→}
 442→
 443→function openQuicklink(link: string, type: QuicklinkType) {
 444→  switch (type) {
 445→    case 'url':
 446→      openUrl(link);
 447→      break;
 448→    case 'deeplink':
 449→      openDeepLink(link);
 450→      break;
 451→    case 'file':
 452→      openDeepLink(`file://${link}`);
 453→      break;
 454→  }
 455→}
