import { isTauri } from '../platform';
import {
  isStringArray,
  storageGet,
  storageRemove,
  storageSet,
} from './storage';

const DB_PATH = 'sqlite:raycast_clone.db';

export interface ClipboardEntryRow {
  id: string;
  content: string;
  content_type: string;
  source_app: string;
  copied_at: string;
  pinned: number;
}

export interface SnippetRow {
  id: string;
  name: string;
  keyword: string;
  content: string;
  category: string;
  tags: string;
  created_at: string;
}

export interface QuicklinkRow {
  id: string;
  name: string;
  link: string;
  type: string;
  application: string | null;
  tags: string;
  created_at: string;
}

export interface NoteRow {
  id: string;
  title: string;
  content: string;
  created_at: string;
  updated_at: string;
}

export interface RecentCommandRow {
  id: number;
  command_id: string;
  used_at: string;
}

export interface SettingRow {
  key: string;
  value: string;
}

type DatabaseInstance = {
  execute(
    query: string,
    bindValues?: unknown[],
  ): Promise<{ rowsAffected: number }>;
  select<T>(query: string, bindValues?: unknown[]): Promise<T>;
};

let dbInstance: DatabaseInstance | undefined;
let dbPromise: Promise<DatabaseInstance> | undefined;

async function loadDb(): Promise<DatabaseInstance> {
  const Database = (await import('@tauri-apps/plugin-sql')).default;
  return Database.load(DB_PATH);
}

function getDb(): Promise<DatabaseInstance> {
  if (dbInstance) return Promise.resolve(dbInstance);
  if (dbPromise) return dbPromise;

  dbPromise = loadDb()
    .then(db => {
      dbInstance = db;
      return db;
    })
    .catch(err => {
      dbPromise = undefined;
      throw err;
    });

  return dbPromise;
}

